module RefModule(
  input op,
  input [3:0] a,
  input [3:0] b,
  output [3:0] result,
  output carry
);reg [4:0] unused_temp_result;
  reg temp_carry;

  always @(*) begin
    if (op == 0) begin
      unused_temp_result = a + b;
      temp_carry = (unused_temp_result[4] == 1);
    end else begin
      unused_temp_result = a - b;
      temp_carry = 0;
    end
  end

  assign result = unused_temp_result[3:0];
  assign carry = temp_carry;

endmodule
